library ieee;
use ieee.std_logic_1164.all;

entity comparator is
  port (
    a : in std_logic_vector(15 downto 0);
    b : in std_logic_vector(15 downto 0);
    result : out std_logic_vector(2 downto 0)
  );
end entity;

architecture rtl of comparator is
begin
  process(a)
  begin
    if (a > b) then
      result <= "001";
    elsif (a < b) then
      result <= "010";
    else
      result <= "100";
    end if;
  end process;
end architecture;

